1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.10;
3	
4	const BASE_PRICE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	function singleItemPremium(item: { type: string }): number {
13	  const base = BASE_PRICE[item.type];
14	  return base + base * FIRST_INSURANCE_RATE;
15	}
16	
17	function itemPremium(items: { type: string }[]): number {
18	  return items.reduce((sum, item) => sum + singleItemPremium(item), 0);
19	}
20	
21	export function quote(
22	  policy: { customer: { years: number }; items: { type: string }[] },
23	  _options: { isFollowUp: boolean }
24	): { premium: number } {
25	  return { premium: itemPremium(policy.items) + PROCESSING_FEE };
26	}
